#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char S[100005]; scanf("%s", S);
        long long ans = 0;
        for(int i=1;i<=N;i++){
            int left_ok = (i==1) || (S[i-2]=='0');
            int right_ok = (i==N) || (S[i-1]=='1');
            if(left_ok && right_ok) ans++;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

