const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const S = input[idx++] || '';
  let ans = 0;
  for (let i = 1; i <= N; i++) {
    const leftOk = (i === 1) || (S[i - 2] === '0');
    const rightOk = (i === N) || (S[i - 1] === '1');
    if (leftOk && rightOk) ans++;
  }
  results.push(String(ans));
}
console.log(results.join('\n'));

